import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        Map<String, Integer> ages = new HashMap<>();
        ages.put("Aman", 21);
        ages.put("Priya", 23);

        System.out.println(ages.get("Aman"));
        System.out.println(ages.containsKey("Priya"));
        System.out.println(ages.containsKey("Rahul"));

        ages.put("Aman", 22); // same key -- overwrites the old value
        System.out.println(ages.get("Aman"));
    }
}

import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        Map<String, Integer> ages = new HashMap<>();
        ages.put("Aman", 21);
        ages.put("Priya", 23);

        for (Map.Entry<String, Integer> entry : ages.entrySet()) {
            System.out.println(entry.getKey() + " is " + entry.getValue());
        }
    }
}

import java.util.Map;
import java.util.TreeMap;

public class Main {
    public static void main(String[] args) {
        Map<String, Integer> ages = new TreeMap<>();
        ages.put("Priya", 23);
        ages.put("Aman", 21);
        ages.put("Rahul", 25);

        System.out.println(ages);
    }
}

import java.util.HashMap;
import java.util.Map;

public class Main {
    public static void main(String[] args) {
        String[] words = {"apple", "banana", "apple", "cherry", "banana", "apple"};
        Map<String, Integer> counts = new HashMap<>();

        for (String word : words) {
            counts.put(word, counts.getOrDefault(word, 0) + 1);
        }

        System.out.println(counts.get("apple"));
        System.out.println(counts.get("banana"));
        System.out.println(counts.get("cherry"));
    }
}

